122	
123	    let mut url = base_url.trim_end_matches('/').to_string();
124	
125	    // Auto-fix OpenRouter URLs (users often provide just the domain or the
126	    // completions endpoint). Only rewrite when the URL's host is literally
127	    // openrouter.ai — substring matching would let `evil.com/openrouter.ai`
128	    // hijack the rewrite and leak the bearer token.
129	    let is_openrouter = host_is(&url, "openrouter.ai");
130	    if is_openrouter {
131	        url = "https://openrouter.ai/api/v1".to_string();
132	    } else if url.ends_with("/chat/completions") {
133	        url = url.trim_end_matches("/chat/completions").to_string();
134	    }
135	
136	    // Try OpenAI-standard /v1/models first (works for OpenRouter, LM Studio, vLLM, etc.)
137	    let models_url = if url.ends_with("/v1") {
138	        format!("{url}/models")
139	    } else {
140	        format!("{url}/v1/models")
141	    };
142	
143	    let mut request = client.get(&models_url);
144	    if let Some(key) = api_key {
145	        request = request.bearer_auth(key);
146	    }
