193	pub fn stream_chat(
194	    params: ChatParams,
195	    tx: mpsc::UnboundedSender<StreamEvent>,
196	    cancel: CancellationToken,
197	) {
198	    tokio::spawn(async move {
199	        let ChatParams {
200	            base_url,
201	            model,
202	            messages,
203	            temperature,
204	            max_tokens,
205	            top_p,
206	            frequency_penalty,
207	            presence_penalty,
208	            stop_sequences,
209	            api_key,
210	        } = params;
211	        let client = match Client::builder().connect_timeout(CONNECT_TIMEOUT).build() {
212	            Ok(c) => c,
213	            Err(e) => {
214	                let _ = tx.send(StreamEvent::Error(format!(
215	                    "Failed to create HTTP client: {e}"
216	                )));
217	                return;
218	            }
219	        };
220	        let mut base_url = base_url.trim_end_matches('/').to_string();
221	
222	        let is_openrouter = host_is(&base_url, "openrouter.ai");
223	        if is_openrouter {
224	            base_url = "https://openrouter.ai/api/v1".to_string();
225	        } else if base_url.ends_with("/chat/completions") {
226	            base_url = base_url.trim_end_matches("/chat/completions").to_string();
227	        }
228	
229	        let url = format!("{}/chat/completions", base_url);
230	
231	        let req = ChatRequest {
232	            model,
233	            messages,
234	            stream: true,
235	            temperature,
236	            max_tokens,
237	            top_p,
238	            frequency_penalty,
239	            presence_penalty,
240	            stop_sequences,
241	        };
242	
243	        let mut request = client.post(&url).json(&req);
244	        if let Some(key) = &api_key {
245	            request = request.bearer_auth(key);
246	        }
247	        if is_openrouter {
248	            request = request
249	                .header("HTTP-Referer", "https://github.com/hhheath/hChat")
250	                .header("X-Title", "hChat");
251	        }
252	
253	        let resp = match request.send().await {
254	            Ok(r) => r,
255	            Err(e) => {
256	                let _ = tx.send(StreamEvent::Error(format!("Request failed: {e}")));
257	                return;
258	            }
259	        };
260	
261	        if !resp.status().is_success() {
262	            let status = resp.status();
263	            let body = resp
264	                .bytes()
265	                .await
266	                .map(|b| {
267	                    let truncated = &b[..b.len().min(MAX_ERROR_BODY)];
268	                    String::from_utf8_lossy(truncated).into_owned()
269	                })
270	                .unwrap_or_default();
271	            // Log full error for debugging but only show sanitized message in UI
272	            eprintln!("API error {status}: {body}");
273	            let message = match status.as_u16() {
274	                401 => format!("{status}: Authentication failed — check your API key"),
275	                403 => format!("{status}: Access denied"),
276	                404 => format!("{status}: Endpoint not found — check your URL"),
277	                429 => format!("{status}: Rate limited — try again later"),
278	                500..=599 => format!("{status}: Server error"),
279	                _ => format!("{status}: Request failed"),
280	            };
281	            let _ = tx.send(StreamEvent::Error(message));
282	            return;
283	        }
284	
285	        let mut stream = resp.bytes_stream();
286	        // Use a byte buffer to handle UTF-8 sequences split across chunks
287	        let mut raw_buf: Vec<u8> = Vec::new();
288	
289	        loop {
290	            tokio::select! {
291	                _ = cancel.cancelled() => {
292	                    let _ = tx.send(StreamEvent::Done);
293	                    return;
294	                }
295	                chunk = stream.next() => {
296	                    let Some(chunk) = chunk else {
297	                        let _ = tx.send(StreamEvent::Done);
298	                        return;
299	                    };
300	
301	                    let bytes = match chunk {
302	                        Ok(b) => b,
303	                        Err(e) => {
304	                            let _ = tx.send(StreamEvent::Error(format!("Stream error: {e}")));
305	                            return;
306	                        }
307	                    };
308	
309	                    if raw_buf.len() + bytes.len() > MAX_STREAM_BUFFER {
310	                        let _ = tx.send(StreamEvent::Error("Stream buffer overflow".to_string()));
311	                        return;
312	                    }
313	
314	                    raw_buf.extend_from_slice(&bytes);
315	
316	                    // Find the last valid UTF-8 boundary to avoid splitting multi-byte chars
317	                    let valid_up_to = match std::str::from_utf8(&raw_buf) {
318	                        Ok(_) => raw_buf.len(),
319	                        Err(e) => e.valid_up_to(),
320	                    };
321	
322	                    if valid_up_to == 0 {
323	                        continue;
324	                    }
325	
326	                    // Safe: we just validated this range is valid UTF-8
327	                    let text = std::str::from_utf8(&raw_buf[..valid_up_to]).unwrap();
328	                    let mut remaining_start = 0;
329	
330	                    for line_end in newline_positions(text) {
331	                        let line = text[remaining_start..line_end].trim();
332	                        remaining_start = line_end + 1;
333	
334	                        if line.is_empty() || line.starts_with(':') {
335	                            continue;
336	                        }
337	
338	                        let data = if let Some(d) = line.strip_prefix("data: ") {
339	                            d.trim()
340	                        } else {
341	                            continue;
342	                        };
343	
344	                        if data == "[DONE]" {
345	                            let _ = tx.send(StreamEvent::Done);
346	                            return;
347	                        }
348	
349	                        if let Ok(chunk) = serde_json::from_str::<ChatChunk>(data) {
350	                            if let Some(choices) = chunk.choices {
351	                                for choice in choices {
352	                                    if let Some(delta) = choice.delta {
353	                                        // Skip empty strings: some providers
354	                                        // (Ollama qwen3 thinking, OpenAI keep-
355	                                        // alives) emit `content: ""` alongside
356	                                        // a reasoning delta. Treating that as
357	                                        // "content arrived" prematurely closes
358	                                        // the <think> block and the next
359	                                        // reasoning delta re-opens a new one,
360	                                        // producing dozens of tiny blocks.
361	                                        if let Some(reasoning) = delta.reasoning
362	                                            && !reasoning.is_empty()
363	                                        {
364	                                            let _ = tx.send(StreamEvent::Reasoning(reasoning));
365	                                        }
366	                                        if let Some(content) = delta.content
367	                                            && !content.is_empty()
368	                                        {
369	                                            let _ = tx.send(StreamEvent::Token(content));
370	                                        }
371	                                    }
372	                                }
373	                            }
374	                            if let Some(usage) = chunk.usage {
375	                                let _ = tx.send(StreamEvent::UsageInfo(usage));
376	                            }
377	                        }
378	                    }
379	
380	                    // Keep unprocessed bytes (incomplete line + any trailing invalid UTF-8)
381	                    let consumed = remaining_start.min(valid_up_to);
382	                    raw_buf = raw_buf[consumed..].to_vec();
383	                }
384	            }
385	        }
386	    });
387	}
388	
389	/// Find all newline positions in a string slice
390	fn newline_positions(s: &str) -> impl Iterator<Item = usize> + '_ {
391	    s.bytes()
392	        .enumerate()
393	        .filter_map(|(i, b)| if b == b'\n' { Some(i) } else { None })
394	}
395	
396	#[cfg(test)]
397	mod tests {
398	    use super::*;
399	
400	    #[tokio::test]
401	    async fn test_openrouter_fetch() {
402	        let models = fetch_models("https://openrouter.ai/api/v1", None).await;
403	        println!("Result: {:?}", models);
404	    }
405	
406	    #[test]
407	    fn host_is_exact_match() {
408	        assert!(host_is("https://openrouter.ai/api/v1", "openrouter.ai"));
409	        assert!(host_is("https://openrouter.ai", "openrouter.ai"));
410	        assert!(host_is("http://openrouter.ai/foo", "openrouter.ai"));
411	        // Case-insensitive host
412	        assert!(host_is("https://OpenRouter.AI/api", "openrouter.ai"));
413	    }
414	
415	    #[test]
416	    fn host_is_rejects_substring_attacks() {
417	        // Path-component "openrouter.ai" — the credential redirect bug.
418	        assert!(!host_is(
419	            "https://my-proxy.example/openrouter.ai/v1",
420	            "openrouter.ai"
421	        ));
422	        // Subdomain prefix
423	        assert!(!host_is(
424	            "https://openrouter.ai.evil.example/api",
425	            "openrouter.ai"
426	        ));
427	        // Different host
428	        assert!(!host_is("https://openai.com/v1", "openrouter.ai"));
429	    }
430	
431	    #[test]
432	    fn host_is_rejects_unparseable() {
433	        assert!(!host_is("openrouter.ai/api/v1", "openrouter.ai")); // no scheme
434	        assert!(!host_is("not a url", "openrouter.ai"));
435	        assert!(!host_is("", "openrouter.ai"));
436	    }
437	}
