            }
        }
        // Always mark as titled so a transient failure (or empty
        // sanitized result) doesn't trigger a retry on every send.
        self.storage.mark_auto_titled(conv_id);
    }
    self.refresh_conversation_list();
    self.title_rx = None;
}

